import { Component, OnDestroy, OnInit } from '@angular/core';
import { RouterLink } from '@angular/router';
import { CommonModule } from '@angular/common';
import { Pipe, PipeTransform } from '@angular/core';

@Pipe({ name: 'stripHtml', standalone: true })
export class StripHtmlPipe implements PipeTransform {
  transform(value: string): string {
    return value?.replace(/<[^>]*>/g, '') ?? '';
  }
}

interface Slide {
  date: string;
  title: string;
  sub: string;
}

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [RouterLink, CommonModule, StripHtmlPipe],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent implements OnInit, OnDestroy {

  // ── Hero slides ──────────────────────────────────────
  slides: Slide[] = [
    {
      date: '08 septembre 2022',
      title: 'Lancement officiel du logiciel de gestion intégrée des droits, taxes et redevances <em>« LOGIRAD »</em>',
      sub: 'Cérémonie présidée par le Premier Ministre pour marquer le démarrage officiel de la plateforme de gestion des recettes non fiscales en RDC.'
    },
    {
      date: '19 septembre – 21 décembre 2022',
      title: 'Formation de <em>1 080 utilisateurs</em> des provinces du Sud et de l\'Est',
      sub: 'Agents de la DGM, Mines, Hydrocarbures, PTNTIC, Affaires foncières et Environnement formés à l\'utilisation de LOGIRAD.'
    },
    {
      date: '29 décembre 2022',
      title: 'Circulaire ministérielle n°003 sur l\'utilisation <em>obligatoire de LOGIRAD</em>',
      sub: 'Mesures d\'encadrement de la procédure dématérialisée pour optimiser la mobilisation des recettes non fiscales sur l\'ensemble du territoire national.'
    }
  ];

  activeIndex = 0;
  get activeSlide(): Slide { return this.slides[this.activeIndex]; }

  private timer: ReturnType<typeof setInterval> | null = null;

  setSlide(index: number): void {
    this.activeIndex = index;
    this.resetTimer();
  }

  private resetTimer(): void {
    if (this.timer) clearInterval(this.timer);
    this.timer = setInterval(() => {
      this.activeIndex = (this.activeIndex + 1) % this.slides.length;
    }, 5000);
  }

  // ── Stats ────────────────────────────────────────────
  stats = [
    { value: '+4 250', label: 'Utilisateurs formés' },
    { value: '+2 500', label: 'Utilisateurs connectés' },
    { value: '26',     label: 'Provinces couvertes' },
    { value: '2',      label: 'Vagues de déploiement' }
  ];

  // ── What We Offer cards ──────────────────────────────
  offerCards = [
    {
      icon: '🏛️',
      title: 'Accès citoyen',
      description: 'En tant que plus haute juridiction judiciaire, la Cour de cassation examine les appels et assure l\'interprétation uniforme du droit à travers la RDC.'
    },
    {
      icon: '📞',
      title: 'Centre d\'appel',
      description: 'Via notre jurisprudence et nos décisions, nous établissons des précédents juridiques guidant les tribunaux pour une application cohérente de la justice.'
    },
    {
      icon: '⚖️',
      title: 'Dysfonctionnement',
      description: 'Nos magistrats et conseillers sont sélectionnés selon le mérite, garantissant les plus hauts standards d\'expertise juridique, d\'intégrité et d\'engagement.'
    },
    {
      icon: '📋',
      title: 'Texte réglementaire',
      description: 'Nous participons activement au dialogue avec les organes judiciaires internationaux via AJI-UCAF et AJI-AJF pour aligner nos standards.'
    }
  ];

  // ── Integrated service cards ─────────────────────────
  serviceCards = [
    {
      icon: '⚖️',
      title: 'Droit Civil & Commercial',
      items: [
        'Appels des Cours d\'appel',
        'Litiges commerciaux et contrats',
        'Questions de propriété et succession',
        'Affaires de responsabilité civile'
      ]
    },
    {
      icon: '🔒',
      title: 'Droit Pénal',
      items: [
        'Appels en cassation pénale',
        'Erreurs de procédure',
        'Application du droit criminel',
        'Interprétations de condamnation'
      ]
    },
    {
      icon: '👨‍👩‍👧',
      title: 'Droit de la Famille',
      items: [
        'Appels en mariage et divorce',
        'Garde d\'enfants',
        'Questions de succession',
        'Droits de propriété familiale'
      ]
    },
    {
      icon: '👔',
      title: 'Droit du Travail',
      items: [
        'Appels en litiges du travail',
        'Questions de contrat d\'emploi',
        'Protection des droits des travailleurs',
        'Réglementations en milieu de travail'
      ]
    },
    {
      icon: '🏛️',
      title: 'Droit Public',
      items: [
        'Cas de privilège juridictionnel',
        'Poursuites de hauts fonctionnaires',
        'Questions constitutionnelles',
        'Contentieux d\'intérêt public'
      ]
    },
    {
      icon: '🏠',
      title: 'Droits de Propriété',
      items: [
        'Litiges immobiliers',
        'Questions de propriété foncière',
        'Transactions immobilières',
        'Propriété intellectuelle'
      ]
    }
  ];

  // ── Extension section ────────────────────────────────
  assietteServices = ['Mines', 'Hydrocarbures', 'Affaires foncières', 'Environnement', 'PTNTIC & DGM'];

  phases = [
    {
      label: 'Phase 1',
      provinces: 'Kinshasa, Kongo Central, Tshopo, Haut-Uélé, Bas-Uélé, Tanganyika, Haut-Katanga, Haut-Lomami, Lualaba'
    },
    {
      label: 'Phase 2 — 01 juillet 2024',
      provinces: 'Kasaï, Kasaï Central, Kasaï Oriental, Lomami, Sankuru, Maniema, Sud-Kivu'
    }
  ];

  // ── Newsletter ───────────────────────────────────────
  newsItems = [
    {
      icon: '📰',
      bg: 'linear-gradient(135deg,#1a2d4a,#0d1b2e)',
      type: 'Rapport de décision',
      date: '15 Nov 2025',
      title: 'Naviguer les appels : conseils juridiques pour une procédure fluide'
    },
    {
      icon: '🏛️',
      bg: 'linear-gradient(135deg,#1e2a3a,#111d2e)',
      type: 'Mise à jour judiciaire',
      date: '22 Oct 2025',
      title: 'Points clés dans les procédures en cassation'
    },
    {
      icon: '📖',
      bg: 'linear-gradient(135deg,#1c3040,#0d1b2e)',
      type: 'Décision judiciaire',
      date: '18 Oct 2025',
      title: 'Modifications récentes du droit procédural'
    },
    {
      icon: '✊',
      bg: 'linear-gradient(135deg,#2a1a1a,#1a0d0d)',
      type: 'Mise à jour légale',
      date: '12 Oct 2025',
      title: 'Comprendre vos droits dans le processus d\'appel'
    }
  ];

  // ── Lifecycle ────────────────────────────────────────
  ngOnInit(): void {
    this.resetTimer();
  }

  ngOnDestroy(): void {
    if (this.timer) clearInterval(this.timer);
  }
}
